-- migrations/089c_supplemental_close_v2.sql
-- Phase 30 Pattern B step 3: redo the FY2025 supplemental close after 089b reclass.
--
-- 089b moved 13 Toast Payroll FY2025 DR lines ($41,029.94) from Payroll Expenses
-- (expense) to Payroll Clearing (asset). This changed FY2025 NI by +$41,029.94.
-- This migration reverses the old 088b close and posts a fresh one with new residuals.
--
-- New NI residual to RE: $-13,893.88 (was -$54,923.82)
-- Balanced: $124,723.60 DR = $124,723.60 CR across 49 lines

UPDATE closed_periods SET unlocked_at=datetime('now'), unlock_reason='Phase 30 089c re-close', unlocked_by='phase_30_089c' WHERE unlocked_at IS NULL;

UPDATE journal_entries SET status='reversed', notes=COALESCE(notes,'') || ' | 089c re-close 2026-05-20' WHERE id='088a-supplemental-fy2025-close';

VALUES ('089c-supplemental-fy2025-close-v2', '2025-12-31',
  'Phase 30 Pattern B: re-do FY2025 supplemental close after 089b — absorb NI residual $-13893.88',
  'fiscal_year_close', 'phase_30_089c', 124723.6, 124723.6, 'posted', 'phase_30_089c',
  'Replaces 088a-supplemental-fy2025-close after 089b moved Toast Payroll DRs to Payroll Clearing.');


UPDATE closed_periods SET unlocked_at=NULL, unlock_reason=NULL, unlocked_by=NULL WHERE unlock_reason='Phase 30 089c re-close';
